mapper.select:
SELECT
FROM tb_pmb_plan_error_report a LEFT JOIN tb_pmb_plan_list b ON b.id = a.plan_id LEFT JOIN tb_mbm_user c ON c.id = a.create_id LEFT JOIN tb_mbm_admin_user d ON d.id = a.process_manager
ORDER BY FIELD(a.process_sp, '01', '02', '03') ASC, create_date DESC LIMIT #{offset}, #{recordSize}

mapper.insert:
	INSERT INTO tb_pmb_plan_error_report (plan, report_content, memo, process_sp, process_manager, create_id)
	VALUES (
		#{planId},
		#{reportContent},
		#{memo},
		#{processSp},
		#{processManager},
		#{createId}
   );
